        return False
    # split on en-dash, em-dash, hyphen
    parts = re.split('[–—-]', time_range_str)
    if len(parts) < 2:
        return False
    closing = parts[-1].strip()
    close_min = parse_time(closing)
    if close_min is None:
        return False
    return close_min > 18*60  # strictly after 6:00 PM

